def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body (or person) into a single,
    fluent sentence.  The function tries to use a natural phrasing for each
    predicate and joins the resulting clauses with commas and a final “and”.
    """
    if not triples:
        return ""

    # Group triples by subject for better sentence construction
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Identify the main subject (usually the celestial body)
    main_subject = None
    discoverer_subjects = set()

    for t in triples:
        if t.predicate.lower() == "discoverer":
            discoverer_subjects.add(t.object)

    # Find main subject (not a discoverer)
    for subj in subject_triples.keys():
        if subj not in discoverer_subjects:
            main_subject = subj
            break

    if main_subject is None:
        main_subject = list(subject_triples.keys())[0] if subject_triples else None

    # Keep object value with units for better readability
    def clean_obj(obj: str) -> str:
        # Remove parentheses around units and format more naturally
        obj = obj.strip()
        # Handle various unit formats: (kilometres), (kilometrePerSeconds), etc.
        import re
        # Remove parentheses around unit suffixes
        obj = re.sub(r'\s*\(([^)]+)\)', r' \1', obj)

        # Format numbers to remove unnecessary decimal places
        # If it's a number ending in .0, remove the decimal
        try:
            # Check if the object value starts with a number
            num_match = re.match(r'^([\d.]+)', obj)
            if num_match:
                num_str = num_match.group(1)
                try:
                    num_val = float(num_str)
                    if num_val == int(num_val):
                        # Replace with integer version
                        obj = re.sub(r'^[\d.]+', str(int(num_val)), obj)
                except ValueError:
                    pass
        except:
            pass

        return obj.strip()

    # Simple template mapping for common predicates
    def phrase(t: Triple, is_relative_clause: bool = False, combine_with_prev: bool = False) -> str:
        subj, pred, obj = t.subject, t.predicate, t.object
        clean_obj_val = clean_obj(obj)

        # Normalise predicate strings (remove spaces, lower‑case)
        p = pred.strip().lower()

        # For relative clauses (when subject is discoverer/person), use "who"
        relative_start = "who" if is_relative_clause else None

        # Mapping of predicate to a readable clause
        if p == "discoverer":
            if relative_start:
                return f"who was discovered by {clean_obj_val}"
            return f"{subj} was discovered by {clean_obj_val}"
        if p == "discovered":
            if relative_start:
                return f"who was discovered on {clean_obj_val}"
            return f"{subj} was discovered on {clean_obj_val}"
        if p == "epoch":
            return f"{subj} has epoch {clean_obj_val}"
        if p == "apoapsis":
            if combine_with_prev:
                return f"with an apoapsis of {clean_obj_val}"
            return f"{subj} has an apoapsis of {clean_obj_val}"
        if p == "periapsis":
            if combine_with_prev:
                return f"with a periapsis of {clean_obj_val}"
            return f"{subj} has a periapsis of {clean_obj_val}"
        if p == "orbitalperiod":
            if combine_with_prev:
                return f"with an orbital period of {clean_obj_val}"
            return f"{subj} has an orbital period of {clean_obj_val}"
        if p == "averagespeed":
            if combine_with_prev:
                return f"with an average speed of {clean_obj_val}"
            return f"{subj} travels at an average speed of {clean_obj_val}"
        if p == "escapevelocity":
            return f"an escape velocity of {clean_obj_val}" if combine_with_prev else f"{subj} has an escape velocity of {clean_obj_val}"
        if p == "mass":
            if combine_with_prev:
                return f"with a mass of {clean_obj_val}"
            return f"{subj} has a mass of {clean_obj_val}"
        if p == "density":
            if combine_with_prev:
                return f"with a density of {clean_obj_val}"
            return f"{subj} has a density of {clean_obj_val}"
        if p == "temperature":
